 1→import React, { useState } from 'react';
 2→import PromptResponsesModal from './PromptResponsesModal';
 3→
 4→const PromptSection = ({ prompt, responsesData, onWriteResponse }) => {
 5→    const responseCount = responsesData?.uniqueCount || responsesData?.count || 0;
 6→    const seen = new Set();
 7→    const avatars = (responsesData?.responses || []).filter(r => {
 8→        if (seen.has(r.user_id)) return false;
 9→        seen.add(r.user_id);
10→        return true;
11→    }).slice(0, 10);
12→    const [showModal, setShowModal] = useState(false);
13→
14→    return (
15→        <div className="dashboard-prompt">
16→            <div className="dashboard-prompt-header">
17→                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 -960 960 960" fill="currentColor" className="dashboard-prompt-icon">
18→                    <path d="M480-80q-26 0-47-12.5T400-126q-33 0-56.5-23.5T320-206v-142q-59-39-94.5-103T190-590q0-121 84.5-205.5T480-880q121 0 205.5 84.5T770-590q0 77-35.5 140T640-348v142q0 33-23.5 56.5T560-126q-12 21-33 33.5T480-80Zm-80-126h160v-36H400v36Zm0-76h160v-38H400v38Zm-8-118h58v-108l-88-88 42-42 76 76 76-76 42 42-88 88v108h58q54-26 88-76.5T690-590q0-88-61-149t-149-61q-88 0-149 61t-61 149q0 63 34 113.5t88 76.5Z"/>
19→                </svg>
20→                <span className="dashboard-prompt-label">Today's Prompt</span>
21→                {prompt.category && (
22→                    <span className="dashboard-prompt-category">{prompt.category}</span>
23→                )}
24→            </div>
25→            <p className="dashboard-prompt-text">{prompt.prompt_text}</p>
26→            <div className="dashboard-prompt-footer">
27→                <button
28→                    className="dashboard-prompt-write-btn"
29→                    onClick={() => onWriteResponse?.(prompt)}
30→                >
31→                    Write your take <span style={{ marginLeft: '6px' }}>→</span>
32→                </button>
33→                {responseCount > 0 && (
34→                    <div
35→                        className="dashboard-prompt-responses"
36→                        onClick={() => setShowModal(true)}
37→                    >
38→                        <div className="dashboard-prompt-avatars">
39→                            {avatars.map((r, i) => (
40→                                <img
41→                                    key={r.id}
42→                                    src={r.users?.image_url || '/assets/profile.jpg'}
43→                                    alt=""
44→                                    className="dashboard-prompt-avatar"
45→                                    style={{ zIndex: avatars.length - i }}
46→                                />
47→                            ))}
48→                        </div>
49→                        <span className="dashboard-prompt-count">
50→                            {responseCount} {responseCount === 1 ? 'response' : 'responses'}
51→                        </span>
52→                    </div>
53→                )}
54→            </div>
55→
56→            {showModal && (
57→                <PromptResponsesModal
58→                    promptId={prompt.id}
59→                    count={responseCount}
60→                    promptText={prompt.prompt_text}
61→                    onClose={() => setShowModal(false)}
62→                />
