  8→function timeAgo(dateStr) {
  9→    const seconds = Math.floor((Date.now() - new Date(dateStr).getTime()) / 1000);
 10→    if (seconds < 60) return 'just now';
 11→    const minutes = Math.floor(seconds / 60);
 12→    if (minutes < 60) return `${minutes}m ago`;
 13→    const hours = Math.floor(minutes / 60);
 14→    if (hours < 24) return `${hours}h ago`;
 15→    const days = Math.floor(hours / 24);
 16→    if (days < 30) return `${days}d ago`;
 17→    return new Date(dateStr).toLocaleDateString();
 18→}
